/// Deserializes values from a CDR byte buffer.
#[derive(Debug)]
pub struct Reader<'a> {
    buf: &'a [u8],
    pos: usize,
    endian: Endian,
    cursor: Cursor,
    encoding: Encoding,
}

impl<'a> Reader<'a> {
    /// Parse the encapsulation header and position at the body start. The
    /// encoding ([`Encoding`]) and endianness are taken from the representation
    /// identifier, so a reader transparently accepts both XCDR1 (`00 00`/`00 01`)
    /// and PLAIN_CDR2 (`00 06`/`00 07`) payloads.
    pub fn new(buf: &'a [u8]) -> Result<Self, CdrError> {
        if buf.len() < 4 {
            return Err(CdrError::BadEncapsulation);
        }
        let (endian, encoding) = match [buf[0], buf[1]] {
            REPR_CDR_LE => (Endian::Little, Encoding::Xcdr1),
            REPR_CDR_BE => (Endian::Big, Encoding::Xcdr1),
            REPR_CDR2_LE => (Endian::Little, Encoding::Xcdr2),
            REPR_CDR2_BE => (Endian::Big, Encoding::Xcdr2),
            _ => return Err(CdrError::BadEncapsulation),
        };
        Ok(Reader {
            buf,
            pos: 4,
            endian,
            cursor: Cursor { origin: 4 },
            encoding,
        })
    }

    pub fn endian(&self) -> Endian {
        self.endian
    }

    /// The encoding detected from the encapsulation header.
    pub fn encoding(&self) -> Encoding {
        self.encoding
    }

    fn align(&mut self, a: usize) {
        let a = a.min(self.encoding.max_align());
        self.pos += self.cursor.padding(self.pos, a);
    }

    fn take(&mut self, n: usize) -> Result<&'a [u8], CdrError> {
        let end = self.pos.checked_add(n).ok_or(CdrError::Truncated)?;
        let slice = self.buf.get(self.pos..end).ok_or(CdrError::Truncated)?;
        self.pos = end;
        Ok(slice)
    }

    fn get<const N: usize>(&mut self, a: usize) -> Result<[u8; N], CdrError> {
        self.align(a);
        let slice = self.take(N)?;
        let mut arr = [0u8; N];
        arr.copy_from_slice(slice);
        Ok(arr)
    }

    fn decode_u16(&self, b: [u8; 2]) -> u16 {
        match self.endian {
            Endian::Little => u16::from_le_bytes(b),
            Endian::Big => u16::from_be_bytes(b),
        }
    }
    fn decode_u32(&self, b: [u8; 4]) -> u32 {
        match self.endian {
            Endian::Little => u32::from_le_bytes(b),
            Endian::Big => u32::from_be_bytes(b),
        }
    }
    fn decode_u64(&self, b: [u8; 8]) -> u64 {
        match self.endian {
            Endian::Little => u64::from_le_bytes(b),
            Endian::Big => u64::from_be_bytes(b),
        }
    }

    pub fn read_u8(&mut self) -> Result<u8, CdrError> {
        Ok(self.take(1)?[0])
    }
    pub fn read_i8(&mut self) -> Result<i8, CdrError> {
        Ok(self.read_u8()? as i8)
    }
    pub fn read_bool(&mut self) -> Result<bool, CdrError> {
        Ok(self.read_u8()? != 0)
    }

    pub fn read_u16(&mut self) -> Result<u16, CdrError> {
        let b = self.get::<2>(2)?;
        Ok(self.decode_u16(b))
    }
    pub fn read_i16(&mut self) -> Result<i16, CdrError> {
        Ok(self.read_u16()? as i16)
    }

    pub fn read_u32(&mut self) -> Result<u32, CdrError> {
        let b = self.get::<4>(4)?;
        Ok(self.decode_u32(b))
    }
    pub fn read_i32(&mut self) -> Result<i32, CdrError> {
        Ok(self.read_u32()? as i32)
    }
    pub fn read_f32(&mut self) -> Result<f32, CdrError> {
        Ok(f32::from_bits(self.read_u32()?))
    }

    pub fn read_u64(&mut self) -> Result<u64, CdrError> {
        let b = self.get::<8>(8)?;
        Ok(self.decode_u64(b))
    }
    pub fn read_i64(&mut self) -> Result<i64, CdrError> {
        Ok(self.read_u64()? as i64)
    }
    pub fn read_f64(&mut self) -> Result<f64, CdrError> {
        Ok(f64::from_bits(self.read_u64()?))
    }

    /// Read a `string` (length incl. NUL, bytes, NUL).
    pub fn read_string(&mut self) -> Result<String, CdrError> {
        let len = self.read_u32()? as usize;
        if len == 0 {
            return Err(CdrError::BadString);
        }
        let bytes = self.take(len)?;
        if bytes[len - 1] != 0 {
            return Err(CdrError::BadString);
        }
        std::str::from_utf8(&bytes[..len - 1])
            .map(str::to_string)
            .map_err(|_| CdrError::BadUtf8)
    }

    /// Read a sequence length prefix (`uint32` element count).
    ///
    /// The count is validated against the bytes actually left in the buffer
    /// (every element occupies at least one wire byte, even an empty nested
    /// message, which CDR encodes as a dummy octet) — so a malformed prefix
    /// cannot drive an attacker-sized allocation in any decode path.
    pub fn read_seq_len(&mut self) -> Result<usize, CdrError> {
        let n = self.read_u32()? as usize;
        if n > self.buf.len() - self.pos {
            return Err(CdrError::Truncated);
        }
        Ok(n)
    }
}

/// ABI of a ROS string: NUL-terminated pointer + length + capacity.
///
/// # Invariant
/// A `RosString` is always readable: either `size == 0` (and `data` is ignored),
/// or `data` points to `size` initialized, valid-UTF-8 bytes. The fields are
/// **private**, so only three paths construct a value and each upholds this:
/// - `alloc` and CDR decode produce the **owned** form: `data` is an allocation of
///   `capacity` bytes holding the `size` UTF-8 bytes plus a NUL (`size < capacity`),
///   which `free` may later reclaim.
/// - `from_raw_parts` (unsafe) rebuilds a value from a raw triple — the caller
///   discharges the invariant. The crate's zero-copy `borrowed_*` helpers use it
///   to make a **borrowed** value (`capacity == 0`, `data` owned elsewhere).
///
/// The `#[repr(C)]` layout is unchanged, so C/Python still read the triple by
/// offset across the ABI; Rust privacy only bars safe Rust from forging one. That
/// makes the read accessor `as_str` genuinely sound; `free` (ownership) stays
/// `unsafe`.
#[repr(C)]
pub struct RosString {
    data: *mut c_char,
    size: usize,
    capacity: usize,
}

impl RosString {
    /// Borrow the string contents. Sound because the private fields keep the type
    /// invariant: `data` points to `size` valid UTF-8 bytes (or the empty form).
    pub fn as_str(&self) -> &str {
        if self.data.is_null() || self.size == 0 {
            return "";
        }
        // SAFETY: by the type invariant, `data` points to `size` valid UTF-8 bytes.
        unsafe {
            let bytes = core::slice::from_raw_parts(self.data as *const u8, self.size);
            core::str::from_utf8_unchecked(bytes)
        }
    }

    /// Allocate an owning, NUL-terminated copy of `s`.
    pub fn alloc(s: &str) -> Self {
        let mut bytes = s.as_bytes().to_vec();
        bytes.push(0);
        let mut bytes = core::mem::ManuallyDrop::new(bytes);
        RosString {
            data: bytes.as_mut_ptr() as *mut c_char,
            size: bytes.len() - 1,
            capacity: bytes.capacity(),
        }
    }

    /// Rebuild a `RosString` from its raw ABI triple.
    ///
    /// # Safety
    /// The caller must uphold the type invariant: either `size == 0`, or `data`
    /// points to `size` initialized, valid-UTF-8 bytes that stay live for every
    /// read of the returned value. If `capacity > 0`, `data` must be a single
    /// allocation of `capacity` bytes (as produced by `alloc`) so that `free`
    /// can reclaim it; `capacity == 0` marks a borrowed value that must not be
    /// freed and whose backing must outlive it.
    pub unsafe fn from_raw_parts(data: *mut c_char, size: usize, capacity: usize) -> Self {
        RosString {
            data,
            size,
            capacity,
        }
    }

    /// # Safety
    /// Frees the owned buffer, transferring ownership out of `self`; call at most
    /// once per owned value (double-free discipline is the caller's). Idempotent
    /// on null.
    pub unsafe fn free(&mut self) {
        if !self.data.is_null() {
            drop(Vec::from_raw_parts(
                self.data as *mut u8,
                self.capacity,
                self.capacity,
            ));
            self.data = core::ptr::null_mut();
            self.size = 0;
            self.capacity = 0;
        }
    }
}

/// ABI of a ROS sequence: pointer + length + capacity.
